Future<List<MediaAttachment>> _downloadPl006ActiveRecipientMedia({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String messageId,
  required int expectedCount,
}) async {
  var attachments = <MediaAttachment>[];
  await waitForCondition(() async {
    attachments = await stack.mediaAttachmentRepo.getAttachmentsForMessage(
      messageId,
    );
    return attachments.length == expectedCount;
  }, timeout: const Duration(seconds: 120));

  final mediaFileManager = MediaFileManager();
  for (final attachment in attachments) {
    if (attachment.downloadStatus == 'done') {
      continue;
    }
    await downloadMedia(
      bridge: stack.bridge,
      mediaAttachmentRepo: stack.mediaAttachmentRepo,
      mediaFileManager: mediaFileManager,
      attachment: attachment,
      contactPeerId: groupId,
      enforceGroupMediaPolicy: true,
    );
  }

  await waitForCondition(() async {
    attachments = await stack.mediaAttachmentRepo.getAttachmentsForMessage(
      messageId,
    );
    return attachments.length == expectedCount &&
        attachments.every((attachment) => attachment.downloadStatus == 'done');
  }, timeout: const Duration(seconds: 120));
  return attachments;
}

Future<Map<String, dynamic>> _attemptPl006DirectMediaDownload({
  required GroupMultiDeviceTestStack stack,
  required String blobId,
}) async {
  final tempDir = await Directory.systemTemp.createTemp(
    'pl006_removed_download_',
  );
  final outputPath = '${tempDir.path}/$blobId.bin';
  try {
    final result = await callP2PMediaDownload(
      stack.bridge,
      id: blobId,
      outputPath: outputPath,
    ).timeout(const Duration(seconds: 45));
    final outputFile = File(outputPath);
    final outputExists = await outputFile.exists();
    final outputBytes = outputExists ? await outputFile.length() : 0;
    return <String, dynamic>{
      ...result,
      'directDownloadDenied': result['ok'] != true,
      'outputPath': outputPath,
      'outputBytes': outputBytes,
      'noDirectDownloadPlaintext': result['ok'] != true && outputBytes == 0,
      'errorMessage': result['errorMessage'],
    };
  } catch (error) {
    final outputFile = File(outputPath);
    final outputExists = await outputFile.exists();
    final outputBytes = outputExists ? await outputFile.length() : 0;
    return <String, dynamic>{
      'ok': false,
      'directDownloadDenied': true,
      'outputPath': outputPath,
      'outputBytes': outputBytes,
      'noDirectDownloadPlaintext': outputBytes == 0,
      'errorMessage': error.toString(),
    };
  }
}

Future<Map<String, dynamic>> _sendProofReaction({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String messageId,
  required String key,
  required String emoji,
}) async {
  final stopwatch = Stopwatch()..start();
  final result = await sendGroupReaction(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    msgRepo: stack.groupMsgRepo,
    reactionRepo: stack.reactionRepo,
    reactionReplayOutboxRepo: stack.reactionReplayOutboxRepo,
    groupId: groupId,
    messageId: messageId,
    emoji: emoji,
    senderPeerId: stack.identity.peerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
  );
  stopwatch.stop();

  final reaction = result.$2;
  final sent = <String, dynamic>{
    'key': key,
    'groupId': groupId,
    'messageId': messageId,
    'outcome': result.$1.name,
    'senderPeerId': stack.identity.peerId,
    'emoji': emoji,
    if (reaction != null) 'reactionId': reaction.id,
    if (reaction != null) 'timestamp': reaction.timestamp,
    'sendMs': stopwatch.elapsedMilliseconds,
    'accepted': result.$1 == SendGroupReactionResult.success,
  };
  if (result.$1 != SendGroupReactionResult.success || reaction == null) {
    writeSharedJson(_signalName('${_role}_reaction_$key.json'), sent);
    throw StateError('$_role failed to send reaction $key: ${result.$1.name}');
  }

  final stored = await _reactionStorageProof(
    stack: stack,
    key: key,
    messageId: messageId,
    reactorPeerId: stack.identity.peerId,
    emoji: emoji,
    streamReceived: false,
  );
  sent['localReactionCount'] = stored['persistedReactionCount'];
  writeSharedJson(_signalName('${_role}_reaction_$key.json'), sent);
  return sent;
}

Future<Map<String, dynamic>> _reactionStorageProof({
  required GroupMultiDeviceTestStack stack,
  required String key,
  required String messageId,
  required String reactorPeerId,
  required String emoji,
  required bool streamReceived,
  String? changeType,
  Duration timeout = const Duration(seconds: 120),
}) async {
  final stopwatch = Stopwatch()..start();
  await waitForCondition(() async {
    final reactions = await stack.reactionRepo.getReactionsForMessage(
      messageId,
    );
    return reactions.any(
      (reaction) =>
          reaction.senderPeerId == reactorPeerId && reaction.emoji == emoji,
    );
  }, timeout: timeout);
  await Future<void>.delayed(const Duration(seconds: 2));

  final reactions = await stack.reactionRepo.getReactionsForMessage(messageId);
  final matches = reactions
      .where(
        (reaction) =>
            reaction.senderPeerId == reactorPeerId && reaction.emoji == emoji,
      )
      .toList(growable: false);
  final proof = <String, dynamic>{
    'key': key,
    'messageId': messageId,
    'reactorPeerId': reactorPeerId,
    'emoji': emoji,
    'streamReceived': streamReceived,
    'changeType': ?changeType,
    'persistedReactionCount': matches.length,
    if (matches.isNotEmpty) 'reactionId': matches.first.id,
    'e2eMs': stopwatch.elapsedMilliseconds,
    'appliedOnceToTarget': matches.length == 1,
  };
  writeSharedJson(_signalName('${_role}_reaction_observed_$key.json'), proof);
  return proof;
}

Future<Map<String, dynamic>> _waitForReactionChangeAndStorage({
  required GroupMultiDeviceTestStack stack,
  required Future<ReactionChange> changeFuture,
  required String key,
  required String messageId,
  required String reactorPeerId,
  required String emoji,
}) async {
  final change = await changeFuture.timeout(const Duration(seconds: 120));
  if (change.messageId != messageId ||
      change.senderPeerId != reactorPeerId ||
      change.reaction?.emoji != emoji) {
    throw StateError(
      '$_role observed unexpected reaction change for $key: '
      'message=${change.messageId} sender=${change.senderPeerId} '
      'emoji=${change.reaction?.emoji}',
    );
  }
  return _reactionStorageProof(
    stack: stack,
    key: key,
    messageId: messageId,
    reactorPeerId: reactorPeerId,
    emoji: emoji,
    streamReceived: true,
    changeType: change.type.name,
  );
}

String _ra013IdentityString(
  Map<String, Map<String, dynamic>> identities,
  String role,
  String key,
) {
  final value = identities[role]?[key] as String?;
  if (value == null || value.trim().isEmpty) {
    throw StateError('RA-013 missing $key for $role identity');
  }
  return value.trim();
}

GroupMemberDeviceIdentity _ra013DeviceIdentity(
  Map<String, Map<String, dynamic>> identities,
  String role,
) {
  final transportPeerId = _ra013IdentityString(
    identities,
    role,
    'transportPeerId',
  );
  final mlKemPublicKey = _ra013IdentityString(
    identities,
    role,
    'mlKemPublicKey',
  );
  return GroupMemberDeviceIdentity(
    deviceId: transportPeerId,
    transportPeerId: transportPeerId,
    deviceSigningPublicKey: _ra013IdentityString(identities, role, 'publicKey'),
    mlKemPublicKey: mlKemPublicKey,
    keyPackageId: defaultGroupWelcomeKeyPackageIdForDevice(transportPeerId),
    keyPackagePublicMaterial: mlKemPublicKey,
  );
}

GroupMember _ra013CharlieMemberWithPhoneAndTablet({
  required String groupId,
  required Map<String, Map<String, dynamic>> identities,
}) {
  return GroupMember(
    groupId: groupId,
    peerId: _ra013IdentityString(identities, 'charlie', 'peerId'),
    username:
        identities['charlie']!['username'] as String? ??
        _usernameForRole('charlie'),
    role: MemberRole.writer,
    publicKey: _ra013IdentityString(identities, 'charlie', 'publicKey'),
    mlKemPublicKey: _ra013IdentityString(
      identities,
      'charlie',
      'mlKemPublicKey',
    ),
    devices: <GroupMemberDeviceIdentity>[
      _ra013DeviceIdentity(identities, 'charlie'),
      _ra013DeviceIdentity(identities, 'dana'),
    ],
    joinedAt: DateTime.now().toUtc(),
  );
}

Future<GroupMember> _waitForMemberDeviceCount({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String memberPeerId,
  required int expectedDeviceCount,
}) async {
  GroupMember? member;
  var nextDrainAt = DateTime.fromMillisecondsSinceEpoch(0);
  await waitForCondition(() async {
    if (DateTime.now().isAfter(nextDrainAt)) {
      nextDrainAt = DateTime.now().add(const Duration(seconds: 2));
      try {
        await drainGroupOfflineInboxForGroup(
          bridge: stack.bridge,
          groupRepo: stack.groupRepo,
          msgRepo: stack.groupMsgRepo,
          groupId: groupId,
          groupMessageListener: stack.groupListener,
          selfPeerId: stack.identity.peerId,
        );
      } catch (error) {
        stdout.writeln(
          '[GMP][$_role] drain while waiting for RA-013 member devices failed: $error',
        );
      }
    }
    member = await stack.groupRepo.getMember(groupId, memberPeerId);
    return (member?.activeDevices.length ?? 0) >= expectedDeviceCount;
  }, timeout: const Duration(seconds: 120));
  return member!;
}

Future<PendingGroupInvite> _createRa013DeviceBoundInvite({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String recipientRole,
  required String outputName,
  required Map<String, Map<String, dynamic>> identities,
}) async {
  final recipientPeerId = _ra013IdentityString(identities, 'charlie', 'peerId');
  final recipientDevice = _ra013DeviceIdentity(identities, recipientRole);
  final keyInfo = await stack.groupRepo.getLatestKey(groupId);
  if (keyInfo == null || keyInfo.keyGeneration <= 0) {
    throw StateError('RA-013 missing latest group key before invite');
  }
  final freshness = await loadCurrentInviteMembershipFreshnessState(
    groupRepo: stack.groupRepo,
    groupId: groupId,
    inviterPeerId: stack.identity.peerId,
    trustedInviterPublicKey: stack.identity.publicKey,
  );
  if (freshness == null) {
    throw StateError('RA-013 missing current invite freshness state');
  }
  final senderDeviceId = stack.p2pService.currentState.peerId;
  final senderDevice = freshness.inviterMember.findDeviceById(senderDeviceId);

  final now = DateTime.now().toUtc();
  final inviteId = 'ra013-$recipientRole-$_runId';
  final expiresAt = now.add(pendingGroupInviteTtl);
  final keyPackageId = recipientDevice.keyPackageId;
  final keyPackagePublicMaterial = recipientDevice.keyPackagePublicMaterial;
  if (keyPackageId == null ||
      keyPackageId.isEmpty ||
      keyPackagePublicMaterial == null ||
      keyPackagePublicMaterial.isEmpty ||
      recipientDevice.mlKemPublicKey == null ||
      recipientDevice.mlKemPublicKey!.isEmpty) {
    throw StateError('RA-013 recipient device lacks welcome package material');
  }
  final welcomePackage = GroupWelcomeKeyPackage.create(
    packageId: keyPackageId,
    publicMaterial: keyPackagePublicMaterial,
    recipientPeerId: recipientPeerId,
    recipientDeviceId: recipientDevice.deviceId,
    recipientTransportPeerId: recipientDevice.transportPeerId,
    recipientMlKemPublicKey: recipientDevice.mlKemPublicKey!,
    inviteId: inviteId,
    groupId: groupId,
    keyEpoch: keyInfo.keyGeneration,
    issuedAt: now,
    expiresAt: expiresAt,
  );
  if (!welcomePackage.isStructurallyValid(at: now)) {
    throw StateError('RA-013 welcome package is structurally invalid');
  }

  final payload = GroupInvitePayload(
    id: inviteId,
    groupId: groupId,
    groupKey: keyInfo.encryptedKey,
    keyEpoch: keyInfo.keyGeneration,
    groupConfig: freshness.groupConfig,
    senderPeerId: stack.identity.peerId,
    senderUsername: stack.identity.username,
    timestamp: now.toIso8601String(),
    recipientPeerId: recipientPeerId,
    recipientDeviceId: recipientDevice.deviceId,
    recipientTransportPeerId: recipientDevice.transportPeerId,
    recipientMlKemPublicKey: recipientDevice.mlKemPublicKey,
    recipientKeyPackageId: keyPackageId,
    recipientKeyPackagePublicMaterial: keyPackagePublicMaterial,
    welcomeKeyPackage: welcomePackage,
    senderDeviceId: senderDevice?.deviceId,
    senderTransportPeerId: senderDevice?.transportPeerId,
    senderDeviceSigningPublicKey: senderDevice?.deviceSigningPublicKey,
    senderKeyPackageId: senderDevice?.keyPackageId,
    invitePolicy: GroupInvitePolicy(
      expiresAt: expiresAt,
      allowedDevices: <String>[recipientDevice.deviceId],
      assignedRole: MemberRole.writer.toValue(),
      canInviteOthers: false,
      joinMaterialKind: GroupInvitePolicy.inlineGroupKeyKind,
      keyEpoch: keyInfo.keyGeneration,
      reusePolicy: GroupInviteReusePolicy.singleUse,
      welcomeKeyPackageId: welcomePackage.packageId,
      welcomeKeyPackagePublicMaterialHash: welcomePackage.publicMaterialHash,
      welcomeKeyPackageExpiresAt: welcomePackage.expiresAt,
    ),
    membershipFreshnessProof: freshness.buildProof(
      inviteId: inviteId,
      groupId: groupId,
      recipientPeerId: recipientPeerId,
      recipientDeviceId: recipientDevice.deviceId,
      recipientTransportPeerId: recipientDevice.transportPeerId,
      recipientMlKemPublicKey: recipientDevice.mlKemPublicKey,
      recipientKeyPackageId: keyPackageId,
      recipientKeyPackagePublicMaterial: keyPackagePublicMaterial,
      inviterDeviceId: senderDevice?.deviceId,
      inviterTransportPeerId: senderDevice?.transportPeerId,
      inviterDeviceSigningPublicKey: senderDevice?.deviceSigningPublicKey,
      inviterKeyPackageId: senderDevice?.keyPackageId,
      keyEpoch: keyInfo.keyGeneration,
      issuedAt: now,
    ),
  );
  if (!payload.isInvitePolicyValid(validationTime: now)) {
    throw StateError('RA-013 device-bound invite policy is invalid');
  }

  final signedPayload = payload.canonicalInviteSignedPayload();
  final signResult = await callSignPayload(
    bridge: stack.bridge,
    dataToSign: signedPayload,
    privateKey: stack.identity.privateKey,
  );
  final signature = signResult['signature'] as String?;
  if (signResult['ok'] != true ||
      signature == null ||
      signature.trim().isEmpty) {
    throw StateError('RA-013 invite signing failed: $signResult');
  }
  final signedInvite = payload.withInviteSignature(
    signature: signature,
    signedPayload: signedPayload,
  );
  final pendingInvite = PendingGroupInvite.fromPayload(
    signedInvite,
    receivedAt: now,
  );
  writeSharedJson(_signalName(outputName), pendingInvite.toMap());
  return pendingInvite;
}

Future<GroupModel> _acceptRa013DeviceInvite({
  required GroupMultiDeviceTestStack stack,
  required PendingGroupInvite invite,
  required String accountPeerId,
  required String accountUsername,
}) async {
  final pendingInviteRepo = InMemoryPendingGroupInviteRepository();
  await pendingInviteRepo.savePendingInvite(invite);
  final ownDeviceId = stack.p2pService.currentState.peerId;
  final (acceptResult, acceptedGroup) = await acceptPendingGroupInvite(
    pendingInviteRepo: pendingInviteRepo,
    groupRepo: stack.groupRepo,
    contactRepo: stack.contactRepo,
    msgRepo: stack.groupMsgRepo,
    bridge: stack.bridge,
    groupId: invite.groupId,
    groupMessageListener: stack.groupListener,
    senderPeerId: accountPeerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
    senderUsername: accountUsername,
    ownDeviceId: ownDeviceId,
    ownTransportPeerId: ownDeviceId,
    ownMlKemPublicKey: stack.identity.mlKemPublicKey,
    ownKeyPackageId: defaultGroupWelcomeKeyPackageIdForDevice(ownDeviceId),
    ownKeyPackagePublicMaterial: stack.identity.mlKemPublicKey,
    drainAcceptedInboxAllPages: true,
  );
  if (acceptResult != AcceptPendingGroupInviteResult.success &&
      acceptResult != AcceptPendingGroupInviteResult.bridgeError) {
    throw StateError('RA-013 invite accept failed: ${acceptResult.name}');
  }
  if (acceptedGroup == null) {
    throw StateError('RA-013 invite accept did not materialize a group');
  }
  return acceptedGroup;
}

Future<Map<String, dynamic>> _sendRa013ProofMessageAsDevice({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String key,
  required String text,
  required String accountPeerId,
  required String accountUsername,
}) async {
  final stopwatch = Stopwatch()..start();
  final messageId = 'gmp_${_runId}_${_scenario}_${key}_$_role';
  final senderDeviceId = stack.p2pService.currentState.peerId;
  final result = await sendGroupMessage(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    msgRepo: stack.groupMsgRepo,
    groupId: groupId,
    text: text,
    senderPeerId: accountPeerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
    senderUsername: accountUsername,
    messageId: messageId,
    senderDeviceId: senderDeviceId,
    senderTransportPeerId: senderDeviceId,
  );
  stopwatch.stop();
  final sent = <String, dynamic>{
    'key': key,
    'messageId': result.$2?.id ?? messageId,
    'groupId': groupId,
    'text': text,
    'outcome': result.$1.name,
    'senderPeerId': accountPeerId,
    'senderUsername': accountUsername,
    'senderDeviceId': senderDeviceId,
    'transportPeerId': senderDeviceId,
    'keyEpoch': result.$2?.keyGeneration ?? await _keyEpoch(stack, groupId),
    if (result.$2 != null)
      'timestamp': result.$2!.timestamp.toUtc().toIso8601String(),
    'recipientPeerIds': _actualDurableRecipientPeerIdsForMessage(
      stack: stack,
      messageId: result.$2?.id ?? messageId,
    ),
    'sendMs': stopwatch.elapsedMilliseconds,
    'accepted':
        result.$1 == SendGroupMessageResult.success ||
        result.$1 == SendGroupMessageResult.successNoPeers,
  };
  if (result.$1 != SendGroupMessageResult.success &&
      result.$1 != SendGroupMessageResult.successNoPeers) {
    throw StateError('$_role failed to send $key: ${result.$1.name}');
  }
  writeSharedJson(_signalName('${_role}_sent_$key.json'), sent);
  return sent;
}

Future<Map<String, dynamic>> _waitForOutboundStatusProof({
  required GroupMultiDeviceTestStack stack,
  required String messageId,
  required String status,
}) async {
  final deadline = DateTime.now().add(const Duration(seconds: 30));
  while (DateTime.now().isBefore(deadline)) {
    final message = await stack.groupMsgRepo.getMessage(messageId);
    if (message?.status == status) {
      return <String, dynamic>{
        'status': message!.status,
        'wireEnvelopePresent': message.wireEnvelope?.isNotEmpty == true,
        'inboxStored': message.inboxStored,
        'inboxRetryPayloadPresent':
            message.inboxRetryPayload?.isNotEmpty == true,
      };
    }
    await Future<void>.delayed(const Duration(milliseconds: 250));
  }
  final message = await stack.groupMsgRepo.getMessage(messageId);
  throw TimeoutException(
    '$_role timed out waiting for $messageId status=$status; '
    'latest=${message?.status}',
  );
}

Future<Map<String, dynamic>> _sendGo002InboxFailureProofMessage({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String text,
}) async {
  final stopwatch = Stopwatch()..start();
  final messageId =
      'gmp_${_runId}_${_scenario}_${_go002AliceInboxFailureKey}_$_role';
  final currentTransportPeerId = stack.p2pService.currentState.peerId?.trim();
  final failureBridge = _InboxStoreFailureBridge(stack.bridge);
  final result = await sendGroupMessage(
    bridge: failureBridge,
    groupRepo: stack.groupRepo,
    msgRepo: stack.groupMsgRepo,
    groupId: groupId,
    text: text,
    senderPeerId: stack.identity.peerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
    senderUsername: stack.identity.username,
    messageId: messageId,
    senderDeviceId: currentTransportPeerId,
    senderTransportPeerId: currentTransportPeerId,
  );
  stopwatch.stop();

  if (result.$1 != SendGroupMessageResult.success) {
    throw StateError('GO-002 Alice publish must succeed: ${result.$1.name}');
  }
  final beforeRetry = await stack.groupMsgRepo.getMessage(messageId);
  if (beforeRetry?.status != 'pending' ||
      beforeRetry?.inboxStored != false ||
      beforeRetry?.inboxRetryPayload == null) {
    throw StateError(
      'GO-002 Alice row must be pending and retryable before retry; '
      'status=${beforeRetry?.status} '
      'inboxStored=${beforeRetry?.inboxStored} '
      'retryPayload=${beforeRetry?.inboxRetryPayload != null}',
    );
  }

  final failedRecipientPeerIds = _failedInboxStoreRecipientPeerIdsForMessage(
    bridge: failureBridge,
    messageId: messageId,
  );
  final publishResponse = _groupPublishResponseForMessage(
    stack: stack,
    messageId: messageId,
  );
  final actualTopicPeers = _intFromBridgeValue(publishResponse?['topicPeers']);
  if (publishResponse?['ok'] != true) {
    throw StateError('GO-002 publish response must be ok: $publishResponse');
  }
  if (actualTopicPeers == null || actualTopicPeers <= 0) {
    throw StateError(
      'GO-002 requires live PubSub publish proof with topicPeers > 0; '
      'topicPeers=$actualTopicPeers',
    );
  }

  final retried = await retryFailedGroupInboxStores(
    bridge: stack.bridge,
    msgRepo: stack.groupMsgRepo,
  );
  final afterRetry = await stack.groupMsgRepo.getMessage(messageId);
  if (retried != 1 ||
      afterRetry?.status != 'sent' ||
      afterRetry?.inboxStored != true ||
      afterRetry?.inboxRetryPayload != null) {
    throw StateError(
      'GO-002 retry must promote sender row to sent; retried=$retried '
      'status=${afterRetry?.status} '
      'inboxStored=${afterRetry?.inboxStored} '
      'retryPayload=${afterRetry?.inboxRetryPayload != null}',
    );
  }

  final retriedRecipientPeerIds = _actualDurableRecipientPeerIdsForMessage(
    stack: stack,
    messageId: messageId,
  );
  final sent = <String, dynamic>{
    'key': _go002AliceInboxFailureKey,
    'messageId': messageId,
    'text': text,
    'outcome': result.$1.name,
    'senderPeerId': stack.identity.peerId,
    'senderUsername': stack.identity.username,
    'senderDeviceId': stack.p2pService.currentState.peerId,
    'transportPeerId': stack.p2pService.currentState.peerId,
    'timestamp': (result.$2?.timestamp.toUtc() ?? DateTime.now().toUtc())
        .toIso8601String(),
    'keyEpoch': result.$2?.keyGeneration ?? await _keyEpoch(stack, groupId),
    'recipientPeerIds': retriedRecipientPeerIds,
    'failedInboxRecipientPeerIds': failedRecipientPeerIds,
    'forcedInboxStoreFailure': true,
    'senderStatusBeforeRetry': beforeRetry!.status,
    'inboxStoredBeforeRetry': beforeRetry.inboxStored,
    'retryPayloadBeforeRetry': beforeRetry.inboxRetryPayload != null,
    'retryCount': retried,
    'senderStatusAfterRetry': afterRetry!.status,
    'inboxStoredAfterRetry': afterRetry.inboxStored,
    'retryPayloadAfterRetry': afterRetry.inboxRetryPayload != null,
    'actualDurablePayloadProof': true,
    'topicPeers': actualTopicPeers,
    'actualTopicPeerProof': true,
    'sendMs': stopwatch.elapsedMilliseconds,
  };
  writeSharedJson(
    _signalName('alice_sent_$_go002AliceInboxFailureKey.json'),
    sent,
  );
  return sent;
}

List<String> _actualDurableRecipientPeerIdsForMessage({
  required GroupMultiDeviceTestStack stack,
  required String messageId,
}) {
  final bridge = stack.bridge;
  if (bridge is! RecordingGoBridgeClient) {
    throw StateError('GM proof requires a recording bridge');
  }
  for (final raw in bridge.sentMessages.reversed) {
    final parsed = jsonDecode(raw) as Map<String, dynamic>;
    if (parsed['cmd'] != 'group:inboxStore') continue;
    final payload = parsed['payload'] as Map<String, dynamic>;
    final message = payload['message'];
    if (message is! String) continue;
    final replayEnvelope = jsonDecode(message) as Map<String, dynamic>;
    if (replayEnvelope['messageId'] != messageId) continue;
    return (payload['recipientPeerIds'] as List<dynamic>? ?? const [])
        .map((value) => value.toString())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
  }
  throw StateError('Missing actual group:inboxStore payload for $messageId');
}

List<String> _failedInboxStoreRecipientPeerIdsForMessage({
  required _InboxStoreFailureBridge bridge,
  required String messageId,
}) {
  for (final raw in bridge.failedInboxStoreMessages.reversed) {
    final parsed = jsonDecode(raw) as Map<String, dynamic>;
    final payload = parsed['payload'] as Map<String, dynamic>;
    final message = payload['message'];
    if (message is! String) continue;
    final replayEnvelope = jsonDecode(message) as Map<String, dynamic>;
    if (replayEnvelope['messageId'] != messageId) continue;
    return (payload['recipientPeerIds'] as List<dynamic>? ?? const [])
        .map((value) => value.toString())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
  }
  throw StateError('Missing forced failed group:inboxStore for $messageId');
}

Map<String, dynamic>? _groupPublishPayloadForMessage({
  required GroupMultiDeviceTestStack stack,
  required String messageId,
}) {
  final bridge = stack.bridge;
  if (bridge is! RecordingGoBridgeClient) return null;
  for (final raw in bridge.sentMessages.reversed) {
    final parsed = jsonDecode(raw) as Map<String, dynamic>;
    if (parsed['cmd'] != 'group:publish') continue;
    final payload = parsed['payload'] as Map<String, dynamic>;
    if (payload['messageId'] == messageId) return payload;
  }
  return null;
}

Map<String, dynamic>? _groupPublishResponseForMessage({
  required GroupMultiDeviceTestStack stack,
  required String messageId,
}) {
  final bridge = stack.bridge;
  if (bridge is! RecordingGoBridgeClient) return null;
  for (final exchange in bridge.bridgeExchanges.reversed) {
    final request = jsonDecode(exchange['request']!) as Map<String, dynamic>;
    if (request['cmd'] != 'group:publish') continue;
    final payload = request['payload'] as Map<String, dynamic>;
    if (payload['messageId'] != messageId) continue;
    final response = jsonDecode(exchange['response']!) as Map<String, dynamic>;
    return response;
  }
  return null;
}

Future<List<Map<String, dynamic>>> _actualDurableMediaForMessage({
  required GroupMultiDeviceTestStack stack,
  required String messageId,
}) async {
  final bridge = stack.bridge;
  if (bridge is! RecordingGoBridgeClient) {
    throw StateError('GM proof requires a recording bridge');
  }
  for (final raw in bridge.sentMessages.reversed) {
    final parsed = jsonDecode(raw) as Map<String, dynamic>;
    if (parsed['cmd'] != 'group:inboxStore') continue;
    final payload = parsed['payload'] as Map<String, dynamic>;
    final message = payload['message'];
    if (message is! String) continue;
    final replayEnvelope = jsonDecode(message) as Map<String, dynamic>;
    if (replayEnvelope['messageId'] != messageId) continue;
    final groupId = payload['groupId'] as String? ?? replayEnvelope['groupId'];
    if (groupId is! String || groupId.isEmpty) {
      throw StateError('Missing groupId for actual inbox payload $messageId');
    }
    final durablePayload = await decodeInboxMessage(
      stack.bridge,
      stack.groupRepo,
      <String, dynamic>{'message': message},
      groupId,
    );
    return (durablePayload['media'] as List<dynamic>? ?? const <dynamic>[])
        .whereType<Map>()
        .map((entry) => Map<String, dynamic>.from(entry))
        .toList(growable: false);
  }
  throw StateError('Missing actual group:inboxStore payload for $messageId');
}

List<Map<String, dynamic>> _mediaAttachmentProofs(
  List<MediaAttachment> attachments,
) {
  return attachments
      .map(
        (attachment) => <String, dynamic>{
          'id': attachment.id,
          'messageId': attachment.messageId,
          'mime': attachment.mime,
          'size': attachment.size,
          'mediaType': attachment.mediaType,
          'width': attachment.width,
          'height': attachment.height,
          if (attachment.durationMs != null)
            'durationMs': attachment.durationMs,
          if (attachment.waveform != null) 'waveform': attachment.waveform,
          'downloadStatus': attachment.downloadStatus,
          'localPathPresent': attachment.localPath?.isNotEmpty == true,
          'contentHash': attachment.contentHash,
          'thumbnailHash': attachment.thumbnailHash,
          'hasEncryptionMetadata': attachment.hasEncryptionMetadata,
          'encryptionScheme': attachment.encryptionScheme,
        },
      )
      .toList(growable: false);
}

Future<List<Map<String, dynamic>>> _mediaProofsForMessage({
  required GroupMultiDeviceTestStack stack,
  required String messageId,
}) async {
  final attachments = await stack.mediaAttachmentRepo.getAttachmentsForMessage(
    messageId,
  );
  return _mediaAttachmentProofs(attachments);
}

int? _intFromBridgeValue(Object? value) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  if (value is String) return int.tryParse(value);
  return null;
}

Future<Map<String, dynamic>> _sendLiveOnlyProofMessage({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String key,
  required String text,
}) async {
  final stopwatch = Stopwatch()..start();
  final messageId = 'gmp_${_runId}_${_scenario}_${key}_$_role';
  final currentTransportPeerId = stack.p2pService.currentState.peerId?.trim();
  final publish = await callGroupPublish(
    stack.bridge,
    groupId: groupId,
    text: text,
    senderPeerId: stack.identity.peerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
    senderUsername: stack.identity.username,
    senderDeviceId: currentTransportPeerId,
    senderTransportPeerId: currentTransportPeerId,
    senderDevicePublicKey: stack.identity.publicKey,
    messageId: messageId,
  );
  stopwatch.stop();
  final sent = <String, dynamic>{
    'key': key,
    'messageId': messageId,
    'text': text,
    'outcome': publish['ok'] == true ? 'success' : 'publishFailed',
    'senderPeerId': stack.identity.peerId,
    'senderUsername': stack.identity.username,
    'senderDeviceId': stack.p2pService.currentState.peerId,
    'transportPeerId': stack.p2pService.currentState.peerId,
    'timestamp': DateTime.now().toUtc().toIso8601String(),
    'keyEpoch': await _keyEpoch(stack, groupId),
    'recipientPeerIds': const <String>[],
    'actualDurablePayloadProof': false,
    'durableInboxStored': false,
    'sendMs': stopwatch.elapsedMilliseconds,
  };
  if (publish['ok'] != true) {
    throw StateError('$_role failed to live-publish $key: $publish');
  }
  writeSharedJson(_signalName('${_role}_sent_$key.json'), sent);
  return sent;
}

Future<Map<String, dynamic>> _sendNw001ProofMessage({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String key,
  required String text,
}) async {
  final flowEvents = <Map<String, dynamic>>[];
  debugSetFlowEventSink(flowEvents.add);
  try {
    final stopwatch = Stopwatch()..start();
    final messageId = 'gmp_${_runId}_${_scenario}_${key}_$_role';
    final currentTransportPeerId = stack.p2pService.currentState.peerId?.trim();
    final result = await sendGroupMessage(
      bridge: stack.bridge,
      groupRepo: stack.groupRepo,
      msgRepo: stack.groupMsgRepo,
      groupId: groupId,
      text: text,
      senderPeerId: stack.identity.peerId,
      senderDeviceId: currentTransportPeerId,
      senderTransportPeerId: currentTransportPeerId,
      senderPublicKey: stack.identity.publicKey,
      senderPrivateKey: stack.identity.privateKey,
      senderUsername: stack.identity.username,
      messageId: messageId,
    );
    stopwatch.stop();

    final fanoutEvent = flowEvents.lastWhere(
      (event) =>
          event['event'] == 'GROUP_SEND_MSG_USE_CASE_SUCCESS' ||
          event['event'] == 'GROUP_SEND_MSG_USE_CASE_SUCCESS_NO_PEERS',
      orElse: () => <String, dynamic>{},
    );
    final fanoutDetails = fanoutEvent['details'] is Map
        ? Map<String, dynamic>.from(fanoutEvent['details'] as Map)
        : const <String, dynamic>{};
    final sent = <String, dynamic>{
      'key': key,
      'messageId': result.$2?.id ?? messageId,
      'groupId': groupId,
      'text': text,
      'outcome': result.$1.name,
      'senderPeerId': stack.identity.peerId,
      'senderDeviceId': currentTransportPeerId,
      'transportPeerId': currentTransportPeerId,
      'keyEpoch': result.$2?.keyGeneration ?? await _keyEpoch(stack, groupId),
      if (result.$2 != null)
        'timestamp': result.$2!.timestamp.toUtc().toIso8601String(),
      'topicPeers': ?fanoutDetails['topicPeers'],
      'expectedRecipientCount': ?fanoutDetails['expectedRecipientCount'],
      'liveFanoutState': ?fanoutDetails['liveFanoutState'],
      'inboxStored': ?fanoutDetails['inboxStored'],
      'sendMs': stopwatch.elapsedMilliseconds,
      'accepted': result.$1 == SendGroupMessageResult.success,
    };
    writeSharedJson(_signalName('${_role}_sent_$key.json'), sent);
    return sent;
  } finally {
    debugSetFlowEventSink(null);
  }
}

Future<Map<String, dynamic>> _attemptRejectedProofMessage({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String key,
  required String text,
  bool bindCurrentTransport = false,
}) async {
  final stopwatch = Stopwatch()..start();
  final messageId = 'gmp_${_runId}_${_scenario}_${key}_$_role';
  final currentTransportPeerId = stack.p2pService.currentState.peerId?.trim();
  final result = await sendGroupMessage(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    msgRepo: stack.groupMsgRepo,
    groupId: groupId,
    text: text,
    senderPeerId: stack.identity.peerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
    senderUsername: stack.identity.username,
    messageId: messageId,
    senderDeviceId: bindCurrentTransport ? currentTransportPeerId : null,
    senderTransportPeerId: bindCurrentTransport ? currentTransportPeerId : null,
  );
  stopwatch.stop();
  final sent = <String, dynamic>{
    'key': key,
    'messageId': result.$2?.id ?? messageId,
    'text': text,
    'outcome': result.$1.name,
    'senderPeerId': stack.identity.peerId,
    if (bindCurrentTransport) 'senderDeviceId': currentTransportPeerId,
    if (bindCurrentTransport) 'transportPeerId': currentTransportPeerId,
    'keyEpoch': result.$2?.keyGeneration ?? await _keyEpoch(stack, groupId),
    'sendMs': stopwatch.elapsedMilliseconds,
    'accepted':
        result.$1 == SendGroupMessageResult.success ||
        result.$1 == SendGroupMessageResult.successNoPeers,
  };
  writeSharedJson(_signalName('${_role}_sent_$key.json'), sent);
  return sent;
}

Future<Map<String, dynamic>> _waitForReceivedProofMessage({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String key,
  required String text,
  required String senderPeerId,
  String? quotedMessageId,
  Duration timeout = const Duration(seconds: 120),
  bool drainWhileWaiting = true,
}) async {
  final stopwatch = Stopwatch()..start();
  final deadline = DateTime.now().add(timeout);
  var nextDrainAt = DateTime.fromMillisecondsSinceEpoch(0);
  while (DateTime.now().isBefore(deadline)) {
    if (drainWhileWaiting && DateTime.now().isAfter(nextDrainAt)) {
      nextDrainAt = DateTime.now().add(const Duration(seconds: 2));
      try {
        await drainGroupOfflineInboxForGroup(
          bridge: stack.bridge,
          groupRepo: stack.groupRepo,
          msgRepo: stack.groupMsgRepo,
          groupId: groupId,
          groupMessageListener: stack.groupListener,
          mediaAttachmentRepo: stack.mediaAttachmentRepo,
          selfPeerId: stack.identity.peerId,
        );
      } catch (error) {
        stdout.writeln(
          '[GMP][$_role] drain while waiting for $key failed: $error',
        );
      }
    }

    final matches = await _matchingProofMessages(
      stack: stack,
      groupId: groupId,
      text: text,
      senderPeerId: senderPeerId,
      quotedMessageId: quotedMessageId,
    );
    if (matches.isNotEmpty) {
      await Future<void>.delayed(const Duration(seconds: 2));
      final finalMatches = await _matchingProofMessages(
        stack: stack,
        groupId: groupId,
        text: text,
        senderPeerId: senderPeerId,
        quotedMessageId: quotedMessageId,
      );
      final first = finalMatches.first;
      final mediaProofs = await _mediaProofsForMessage(
        stack: stack,
        messageId: first.id,
      );
      final received = <String, dynamic>{
        'key': key,
        'messageId': first.id,
        'groupId': first.groupId,
        'text': first.text,
        'senderPeerId': first.senderPeerId,
        if (first.senderUsername != null)
          'senderUsername': first.senderUsername,
        'timestamp': first.timestamp.toUtc().toIso8601String(),
        'keyEpoch': first.keyGeneration,
        'isIncoming': first.isIncoming,
        if (first.quotedMessageId != null && first.quotedMessageId!.isNotEmpty)
          'quotedMessageId': first.quotedMessageId,
        'e2eMs': stopwatch.elapsedMilliseconds,
        'persistedCount': finalMatches.length,
        if (mediaProofs.isNotEmpty) 'mediaAttachments': mediaProofs,
        if (mediaProofs.isNotEmpty)
          'mediaAttachmentIds': mediaProofs
              .map((attachment) => attachment['id'] as String)
              .toList(growable: false),
        if (mediaProofs.isNotEmpty)
          'mediaContentHashes': mediaProofs
              .map((attachment) => attachment['contentHash'] as String?)
              .whereType<String>()
              .toList(growable: false),
        if (mediaProofs.isNotEmpty) 'mediaAttachmentCount': mediaProofs.length,
      };
      writeSharedJson(_signalName('${_role}_received_$key.json'), received);
      return received;
    }

    await Future<void>.delayed(const Duration(milliseconds: 250));
  }

  throw TimeoutException('$_role timed out waiting for proof message $key');
}

Future<Map<String, dynamic>> _waitForReceivedProofMessageNoDrain({
