int _notificationCount(GroupMultiDeviceTestStack stack) {
  return stack.notificationService.shown.length +
      stack.notificationService.shownGeneric.length;
}

List<Map<String, dynamic>> _notificationSnapshots(
  GroupMultiDeviceTestStack stack,
) {
  return <Map<String, dynamic>>[
    for (final notification in stack.notificationService.shown)
      <String, dynamic>{
        'kind': 'message',
        'contactPeerId': notification.contactPeerId,
        'senderUsername': notification.senderUsername,
        'messageText': notification.messageText,
        'payload': notification.payload,
      },
    for (final notification in stack.notificationService.shownGeneric)
      <String, dynamic>{
        'kind': 'generic',
        'title': notification.title,
        'body': notification.body,
        'payload': notification.payload,
      },
  ];
}

bool _notificationSnapshotsContainAnyText({
  required List<Map<String, dynamic>> snapshots,
  required Iterable<String> texts,
}) {
  final needles = texts
      .where((text) => text.trim().isNotEmpty)
      .map((text) => text.trim())
      .toList(growable: false);
  if (needles.isEmpty) return false;
  for (final snapshot in snapshots) {
    final haystack = snapshot.values
        .whereType<String>()
        .join('\n')
        .toLowerCase();
    for (final text in needles) {
      if (haystack.contains(text.toLowerCase())) {
        return true;
      }
    }
  }
  return false;
}

Future<void> _waitForNotificationCountAtLeast({
  required GroupMultiDeviceTestStack stack,
  required int count,
}) async {
  await waitForCondition(
    () async => _notificationCount(stack) >= count,
    timeout: const Duration(seconds: 30),
  );
}

