        finalKeyEpochConverged: finalEpoch == epochBefore,
        disconnectDiagnostics: List<Map<String, dynamic>>.from(
          recovery['reconnectDiagnostics'] as List,
        ),
        receivedMessages: receivedMessages,
      ),
    },
  );
}

