  await _waitForRetainedSelfRemoval(stack: stack, groupId: groupId);
  writeSharedText(_signalName('charlie_de017_self_removed'), 'ok');

  await _writeVerdict(
    stack: stack,
    groupId: groupId,
    sentMessages: <Map<String, dynamic>>[
      postAddSent,
      preRemovalSent,
