              ) &&
              memberPeerIds.contains(stack.identity.peerId),
          'memberListIncludesCharlie': memberPeerIds.contains(charliePeerId),
          'receivedAlicePostReaddCurrent':
              (afterReceived['keyEpoch'] as int?) == finalEpoch &&
              finalEpoch >= 2,
          'sentBobPostReaddCurrent':
