Future<Map<String, dynamic>> _up002DurableTimelineProof({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required Map<String, Map<String, dynamic>> identities,
  required String role,
}) async {
  await _restartMl008Listener(stack);
  final timelineTexts = await _timelineTexts(stack: stack, groupId: groupId);
  final addTimelineText = _ml015ReaddTimelineText(identities);
  final removalTimelineText = _ml015RemovalTimelineText(identities);
  final addIndexes = <int>[];
  for (var index = 0; index < timelineTexts.length; index++) {
    if (timelineTexts[index] == addTimelineText) {
      addIndexes.add(index);
    }
  }
  final removalIndex = timelineTexts.indexOf(removalTimelineText);
  final removalCount = timelineTexts
      .where((text) => text == removalTimelineText)
      .length;
  final readdAfterRemoval =
      removalIndex >= 0 && addIndexes.any((index) => index > removalIndex);
  final orderShowsAddRemoveReadd =
      addIndexes.length >= 2 &&
      removalIndex > addIndexes.first &&
      readdAfterRemoval;
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalMemberListIncludesAliceBobCharlie = _ml008HasAllMembers(
    memberPeerIds,
    identities,
  );
  final finalEpoch = await _keyEpoch(stack, groupId);

  return <String, dynamic>{
    'rowId': 'UP-002',
    'role': role,
    'liveThreePartyProof': true,
    'reopenedTimelineRead': true,
    'addTimelineEventCount': addIndexes.length,
    'removeTimelineEventCount': removalCount,
    'timelineContainsInitialAdd': addIndexes.isNotEmpty,
    'timelineContainsRemoval': removalCount > 0,
    'timelineContainsReadd': readdAfterRemoval,
    'timelineOrderShowsAddRemoveReadd': orderShowsAddRemoveReadd,
    'finalMemberListIncludesAliceBobCharlie':
        finalMemberListIncludesAliceBobCharlie,
    'finalStateMatchesTimeline':
        orderShowsAddRemoveReadd && finalMemberListIncludesAliceBobCharlie,
    'finalEpoch': finalEpoch,
  };
}

Future<Map<String, dynamic>> _up006ReaddUiStateProof({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required Map<String, Map<String, dynamic>> identities,
  required String role,
}) async {
  await _restartMl008Listener(stack);
  final timelineTexts = await _timelineTexts(stack: stack, groupId: groupId);
  final removalTimelineText = _ml015RemovalTimelineText(identities);
  final readdTimelineText = _ml015ReaddTimelineText(identities);
  final charlieUsername =
      identities['charlie']!['username'] as String? ??
      _usernameForRole('charlie');
  final removalIndex = timelineTexts.indexOf(removalTimelineText);
  final readdIndex = timelineTexts.indexOf(readdTimelineText, removalIndex + 1);
  final latestCharlieTimelineText = timelineTexts.lastWhere(
    (text) => text.contains(charlieUsername),
    orElse: () => '',
  );
  final latestCharlieTimelineLabel = latestCharlieTimelineText.toLowerCase();
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalMemberListIncludesAliceBobCharlie = _ml008HasAllMembers(
    memberPeerIds,
    identities,
  );
  final finalEpoch = await _keyEpoch(stack, groupId);

  return <String, dynamic>{
    'rowId': 'UP-006',
    'role': role,
    'liveThreePartyProof': true,
    'reopenedTimelineRead': true,
    'timelineContainsRemoval': removalIndex >= 0,
    'timelineContainsReadd': readdIndex >= 0,
    'timelineOrderShowsRemoveBeforeReadd':
        removalIndex >= 0 && readdIndex > removalIndex,
    'readdLabelIsActive':
        latestCharlieTimelineLabel.contains('added') &&
        !latestCharlieTimelineLabel.contains('removed') &&
        !latestCharlieTimelineLabel.contains('invite'),
    'latestCharlieTimelineText': latestCharlieTimelineText,
    'latestCharlieTimelineIsReadd':
        latestCharlieTimelineText == readdTimelineText,
    'staleRemovedStateReused': latestCharlieTimelineText == removalTimelineText,
    'stalePendingInviteStateReused': latestCharlieTimelineText.contains(
      'Invite',
    ),
    'memberListIncludesCharlie': memberPeerIds.contains(
      identities['charlie']!['peerId'] as String,
    ),
    'finalMemberListIncludesAliceBobCharlie':
        finalMemberListIncludesAliceBobCharlie,
    'finalEpoch': finalEpoch,
  };
}

Future<Map<String, dynamic>> _up009ReaddSenderIdentityProof({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required Map<String, Map<String, dynamic>> identities,
  required String role,
  required String charlieMessageId,
}) async {
  final charliePeerId = identities['charlie']!['peerId'] as String;
  final member = await stack.groupRepo.getMember(groupId, charliePeerId);
  final message = await stack.groupMsgRepo.getMessage(charlieMessageId);
  final fallbackLabel = groupPeerFallbackLabel(charliePeerId);
  final renderedSenderDisplayName = message == null
      ? ''
      : resolveGroupSenderDisplayName(
          senderPeerId: message.senderPeerId,
          wireSenderUsername: message.senderUsername,
          member: member,
          preferMemberName: true,
        );
  final currentMemberUsername = member?.username?.trim() ?? '';
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalEpoch = await _keyEpoch(stack, groupId);

  return <String, dynamic>{
    'rowId': 'UP-009',
    'role': role,
    'liveThreePartyProof': true,
    'readdMemberPresent': member != null,
    'charliePostReaddMessageVisible': message != null,
    'charliePostReaddMessageIncoming': message?.isIncoming ?? false,
    'charlieOwnMessageStoredAsSent':
        role == 'charlie' && message != null && !message.isIncoming,
    'senderPeerIdMatchesCharlie': message?.senderPeerId == charliePeerId,
    'messageId': charlieMessageId,
    'storedSenderUsername': message?.senderUsername ?? '',
    'currentMemberUsername': currentMemberUsername,
    'renderedSenderDisplayName': renderedSenderDisplayName,
    'renderedLabelNonBlank': renderedSenderDisplayName.trim().isNotEmpty,
    'renderedLabelMatchesCurrentMember':
        currentMemberUsername.isNotEmpty &&
        renderedSenderDisplayName == currentMemberUsername,
    'renderedLabelNotPeerFallback': renderedSenderDisplayName != fallbackLabel,
    'renderedLabelNotUnknown': renderedSenderDisplayName != 'Unknown',
    'contactIndependentResolution': true,
    'memberListIncludesCharlie': memberPeerIds.contains(charliePeerId),
    'finalMemberListIncludesAliceBobCharlie': _ml008HasAllMembers(
      memberPeerIds,
      identities,
    ),
    'finalEpoch': finalEpoch,
  };
}

Future<Map<String, dynamic>> _up010NotificationRouteProof({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required Map<String, Map<String, dynamic>> identities,
  required String role,
  required String charlieMessageId,
}) async {
  final localPeerId = identities[role]!['peerId'] as String;
  final currentMember = await stack.groupRepo.getMember(groupId, localPeerId);
  final currentRouteDrainCalls = _Counter();
  final currentResolution = await resolveGroupNotificationRouteTarget(
    groupId: groupId,
    groupRepo: stack.groupRepo,
    localPeerId: localPeerId,
    drainOfflineInbox: () async {
      currentRouteDrainCalls.increment();
    },
  );

  var staleRemovedGroupRejected = false;
  var staleRemovedResolutionMissing = false;
  var staleRemovedGroupOpened = false;
  var staleRemovedRecoveryDrainCalls = 0;
  if (currentMember != null) {
    await stack.groupRepo.removeMember(groupId, localPeerId);
    try {
      final staleRouteDrainCalls = _Counter();
      final staleResolution = await resolveGroupNotificationRouteTarget(
        groupId: groupId,
        groupRepo: stack.groupRepo,
        localPeerId: localPeerId,
        drainOfflineInbox: () async {
          staleRouteDrainCalls.increment();
        },
      );
      staleRemovedRecoveryDrainCalls = staleRouteDrainCalls.value;
      staleRemovedGroupOpened = staleResolution.hasGroup;
      staleRemovedResolutionMissing =
          !staleResolution.hasGroup && !staleResolution.hasPendingInvite;
      staleRemovedGroupRejected =
          staleRemovedResolutionMissing && !staleRemovedGroupOpened;
    } finally {
      await stack.groupRepo.saveMember(currentMember);
    }
  }

  final restoredMember = await stack.groupRepo.getMember(groupId, localPeerId);
  final postReaddMessage = await stack.groupMsgRepo.getMessage(
    charlieMessageId,
  );
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalEpoch = await _keyEpoch(stack, groupId);

  return <String, dynamic>{
    'rowId': 'UP-010',
    'role': role,
    'liveThreePartyProof': true,
    'notificationRouteProofSource': 'app_peer_core_simulator',
    'currentLocalMemberPresent': currentMember != null,
    'currentGroupRouteOpened': currentResolution.hasGroup,
    'currentRouteGroupIdMatches': currentResolution.group?.id == groupId,
    'currentRoutePendingInviteAbsent': !currentResolution.hasPendingInvite,
    'currentResolutionRecoveryDrainCalls': currentRouteDrainCalls.value,
    'staleRemovedRecoveryDrainAttempted': staleRemovedRecoveryDrainCalls > 0,
    'staleRemovedGroupRejected': staleRemovedGroupRejected,
    'staleRemovedResolutionMissing': staleRemovedResolutionMissing,
    'staleRemovedGroupOpened': staleRemovedGroupOpened,
    'restoredLocalMemberAfterProbe': restoredMember != null,
    'postReaddMessageVisible': postReaddMessage != null,
    'messageVisibilityMatchesMembership':
        currentResolution.hasGroup &&
        currentMember != null &&
        postReaddMessage != null,
    'finalMemberListIncludesAliceBobCharlie': _ml008HasAllMembers(
      memberPeerIds,
      identities,
    ),
    'finalEpoch': finalEpoch,
  };
}

class _Counter {
  int value = 0;

  void increment() {
    value += 1;
  }
}

Future<void> _runMl015Alice(
  GroupMultiDeviceTestStack stack,
  Map<String, Map<String, dynamic>> identities,
) async {
  final fixture = await _createGroupFixture(
    stack: stack,
    identities: identities,
    memberRoles: const <String>['bob'],
    name: 'ML-015 Private Group',
  );
  writeSharedJson(_signalName('group_fixture.json'), fixture);
  final groupId = (fixture['group'] as Map)['id'] as String;

  await waitForSharedSignal(_signalName('bob_group_joined'));

  final initialCharlieContact = await stack.contactRepo.getContact(
    identities['charlie']!['peerId'] as String,
  );
  if (initialCharlieContact == null) {
    throw StateError('Alice missing Charlie contact before ML-015 initial add');
  }
  final initialAddAt = DateTime.now().toUtc();
  final initialCharlieMember = GroupMember(
    groupId: groupId,
    peerId: initialCharlieContact.peerId,
    username: initialCharlieContact.username,
    role: MemberRole.writer,
    publicKey: initialCharlieContact.publicKey,
    mlKemPublicKey: initialCharlieContact.mlKemPublicKey,
    joinedAt: initialAddAt,
  );
  await addGroupMember(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    groupId: groupId,
    newMember: initialCharlieMember,
    selfPeerId: stack.identity.peerId,
  );
  final initialUpdatedGroup = await stack.groupRepo.getGroup(groupId);
  final initialUpdatedKey = await stack.groupRepo.getLatestKey(groupId);
  final initialUpdatedMembers = await stack.groupRepo.getMembers(groupId);
  writeSharedJson(
    _signalName('charlie_initial_group_fixture.json'),
    buildGroupFixture(
      group: initialUpdatedGroup!,
      keyInfo: initialUpdatedKey!,
      members: initialUpdatedMembers,
    ),
  );
  await waitForSharedSignal(_signalName('charlie_group_joined'));
  await _publishMembersAddedSystemPayload(
    stack: stack,
    groupId: groupId,
    danaMember: initialCharlieMember,
    eventAt: initialAddAt,
    saveLocalTimeline: true,
  );
  await waitForSharedSignal(_signalName('bob_initial_charlie_added'));
  await waitForSharedSignal(_signalName('charlie_initial_charlie_added'));
  await Future<void>.delayed(const Duration(seconds: 5));

  final beforeSent = await _sendProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'aliceBeforeTimelineRemoval',
    text: 'ML-015 Alice before removal $_runId',
  );
  await waitForSharedSignal(
    _signalName('bob_received_aliceBeforeTimelineRemoval'),
  );
  await waitForSharedSignal(
    _signalName('charlie_received_aliceBeforeTimelineRemoval'),
  );
  final alicePreRemovalUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );

  final removedAt = await _removeCharlieAndPublish(
    stack: stack,
    groupId: groupId,
    charlieIdentity: identities['charlie']!,
  );
  await stack.groupMsgRepo.saveMessage(
    buildMemberRemovedTimelineMessage(
      groupId: groupId,
      removedPeerId: identities['charlie']!['peerId'] as String,
      removedUsername: identities['charlie']!['username'] as String?,
      senderId: stack.identity.peerId,
      senderUsername: stack.identity.username,
      eventAt: removedAt,
    ),
  );
  await waitForSharedSignal(_signalName('bob_removed_charlie'));
  await waitForSharedSignal(_signalName('charlie_self_removed'));

  final rejoinKey = await rotateAndDistributeGroupKey(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    groupId: groupId,
    selfPeerId: stack.identity.peerId,
    senderPublicKey: stack.identity.publicKey,
    senderPrivateKey: stack.identity.privateKey,
    senderUsername: stack.identity.username,
    sourceDeviceId: stack.p2pService.currentState.peerId,
    sendP2PMessage: (peerId, message) async {
      await stack.p2pService.sendMessage(peerId, message);
      return true;
    },
  );
  if (rejoinKey == null) {
    throw StateError('ML-015 Alice key rotation failed');
  }
  writeSharedJson(_signalName('rejoin_key.json'), <String, dynamic>{
    'keyEpoch': rejoinKey.keyGeneration,
    'groupKey': rejoinKey.encryptedKey,
  });
  await waitForSharedSignal(_signalName('bob_rotated_key'));

  final removedSent = await _sendProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'aliceDuringTimelineRemoval',
    text: 'ML-015 Alice removed-window message $_runId',
  );
  await waitForSharedSignal(
    _signalName('bob_received_aliceDuringTimelineRemoval'),
  );
  final aliceRemovedWindowUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  await stack.groupMsgRepo.markAsRead(groupId);

  final charlieContact = await stack.contactRepo.getContact(
    identities['charlie']!['peerId'] as String,
  );
  if (charlieContact == null) {
    throw StateError('Alice missing Charlie contact before ML-015 re-add');
  }
  final readdAt = DateTime.now().toUtc();
  final charlieMember = GroupMember(
    groupId: groupId,
    peerId: charlieContact.peerId,
    username: charlieContact.username,
    role: MemberRole.writer,
    publicKey: charlieContact.publicKey,
    mlKemPublicKey: charlieContact.mlKemPublicKey,
    joinedAt: readdAt,
  );
  await addGroupMember(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    groupId: groupId,
    newMember: charlieMember,
    selfPeerId: stack.identity.peerId,
  );
  await _publishMembersAddedSystemPayload(
    stack: stack,
    groupId: groupId,
    danaMember: charlieMember,
    eventAt: readdAt,
    saveLocalTimeline: true,
  );

  final updatedGroup = await stack.groupRepo.getGroup(groupId);
  final updatedKey = await stack.groupRepo.getLatestKey(groupId);
  final updatedMembers = await stack.groupRepo.getMembers(groupId);
  writeSharedJson(
    _signalName('charlie_readd_group_fixture.json'),
    buildGroupFixture(
      group: updatedGroup!,
      keyInfo: updatedKey!,
      members: updatedMembers,
    ),
  );

  await waitForSharedSignal(_signalName('bob_membership_readded'));
  await waitForSharedSignal(_signalName('charlie_group_rejoined'));

  final afterSent = await _sendProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'alicePostTimelineReadd',
    text: 'ML-015 Alice after re-add $_runId',
  );
  await waitForSharedSignal(_signalName('bob_received_alicePostTimelineReadd'));
  await waitForSharedSignal(
    _signalName('charlie_received_alicePostTimelineReadd'),
  );
  await stack.groupMsgRepo.markAsRead(groupId);

  final bobSent = await waitForSharedJson(
    _signalName('bob_sent_bobPostTimelineReadd.json'),
  );
  final bobReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'bobPostTimelineReadd',
    text: bobSent['text'] as String,
    senderPeerId: identities['bob']!['peerId'] as String,
  );
  writeSharedText(_signalName('alice_received_bobPostTimelineReadd'), 'ok');

  final charlieSent = await waitForSharedJson(
    _signalName('charlie_sent_charliePostTimelineReadd.json'),
  );
  final charlieReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'charliePostTimelineReadd',
    text: charlieSent['text'] as String,
    senderPeerId: identities['charlie']!['peerId'] as String,
  );
  writeSharedText(_signalName('alice_received_charliePostTimelineReadd'), 'ok');
  final alicePostReaddUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  await stack.groupMsgRepo.markAsRead(groupId);
  final aliceFinalUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );

  final removalTimelineText = _ml015RemovalTimelineText(identities);
  final readdTimelineText = _ml015ReaddTimelineText(identities);
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalEpoch = await _keyEpoch(stack, groupId);
  final timelineOrderMatches = await _timelineOrderContains(
    stack: stack,
    groupId: groupId,
    orderedTexts: <String>[
      readdTimelineText,
      beforeSent['text'] as String,
      removalTimelineText,
      removedSent['text'] as String,
      readdTimelineText,
      afterSent['text'] as String,
      bobSent['text'] as String,
      charlieSent['text'] as String,
    ],
  );
  await _writeVerdict(
    stack: stack,
    groupId: groupId,
    sentMessages: <Map<String, dynamic>>[beforeSent, removedSent, afterSent],
    receivedMessages: <Map<String, dynamic>>[bobReceived, charlieReceived],
    extra: <String, dynamic>{
      'ml015TimelineTruthProof': <String, dynamic>{
        'rowId': 'ML-015',
        'removedCharlie': true,
        'readdedCharlie': true,
        'removedPeerId': identities['charlie']!['peerId'] as String,
        'sentBeforeRemovalMessage': true,
        'sentRemovedWindowBeforeReadd': true,
        'sentAlicePostReaddMessage': true,
        'receivedBobPostReaddMessage': true,
        'receivedCharliePostReaddMessage': true,
        'timelineOrderMatchesMembershipIntervals': timelineOrderMatches,
        'timelineContainsRemoval': await _hasTimelineText(
          stack: stack,
          groupId: groupId,
          text: removalTimelineText,
        ),
        'timelineContainsReadd': await _hasTimelineText(
          stack: stack,
          groupId: groupId,
          text: readdTimelineText,
        ),
        'memberListIncludesCharlie': memberPeerIds.contains(
          identities['charlie']!['peerId'] as String,
        ),
        'finalEpoch': finalEpoch,
      },
      'up002DurableTimelineProof': await _up002DurableTimelineProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'alice',
      ),
      'up004UnreadChurnProof': <String, dynamic>{
        'rowId': 'UP-004',
        'role': 'alice',
        'liveThreePartyProof': true,
        'preRemovalUnreadCount': alicePreRemovalUnreadCount,
        'removedWindowUnreadCount': aliceRemovedWindowUnreadCount,
        'postReaddUnreadCount': alicePostReaddUnreadCount,
        'postReaddUnreadIncluded': alicePostReaddUnreadCount >= 1,
        'readClearOnOpen': aliceFinalUnreadCount == 0,
        'finalUnreadCountAfterOpen': aliceFinalUnreadCount,
      },
      'up006ReaddUiStateProof': await _up006ReaddUiStateProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'alice',
      ),
      'up009ReaddSenderIdentityProof': await _up009ReaddSenderIdentityProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'alice',
        charlieMessageId: charlieSent['messageId'] as String,
      ),
      'up010NotificationRouteProof': await _up010NotificationRouteProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'alice',
        charlieMessageId: charlieSent['messageId'] as String,
      ),
    },
  );
}

Future<void> _runMl015Bob(
  GroupMultiDeviceTestStack stack,
  Map<String, Map<String, dynamic>> identities,
) async {
  final fixture = await waitForSharedJson(_signalName('group_fixture.json'));
  final groupId = await _importGm004JoinedGroupFixture(
    stack: stack,
    fixture: fixture,
  );
  writeSharedText(_signalName('bob_group_joined'), 'ok');

  var up011BobMuteApplied = false;
  var up011NotificationCountBefore = 0;
  if (_scenario == 'private_timeline_truth') {
    await setGroupMuted(
      groupRepo: stack.groupRepo,
      groupId: groupId,
      isMuted: true,
    );
    up011BobMuteApplied =
        (await stack.groupRepo.getGroup(groupId))?.isMuted == true;
    up011NotificationCountBefore = _notificationCount(stack);
  }

  final alicePeerId = identities['alice']!['peerId'] as String;
  final charliePeerId = identities['charlie']!['peerId'] as String;
  final initialAddTimelineText = _ml015ReaddTimelineText(identities);

  await _waitForMemberInclusion(
    stack: stack,
    groupId: groupId,
    memberPeerId: charliePeerId,
  );
  await waitForCondition(() async {
    return _hasTimelineText(
      stack: stack,
      groupId: groupId,
      text: initialAddTimelineText,
    );
  }, timeout: const Duration(seconds: 120));
  writeSharedText(_signalName('bob_initial_charlie_added'), 'ok');

  final beforeSent = await waitForSharedJson(
    _signalName('alice_sent_aliceBeforeTimelineRemoval.json'),
  );
  final beforeReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'aliceBeforeTimelineRemoval',
    text: beforeSent['text'] as String,
    senderPeerId: alicePeerId,
  );
  writeSharedText(_signalName('bob_received_aliceBeforeTimelineRemoval'), 'ok');
  final bobPreRemovalUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  await stack.groupMsgRepo.markAsRead(groupId);

  await _waitForMemberExclusion(
    stack: stack,
    groupId: groupId,
    removedPeerId: charliePeerId,
  );
  writeSharedText(_signalName('bob_removed_charlie'), 'ok');

  final rotated = await waitForSharedJson(_signalName('rejoin_key.json'));
  await _waitForKeyEpoch(
    stack: stack,
    groupId: groupId,
    keyEpoch: rotated['keyEpoch'] as int,
  );
  writeSharedText(_signalName('bob_rotated_key'), 'ok');

  final removedSent = await waitForSharedJson(
    _signalName('alice_sent_aliceDuringTimelineRemoval.json'),
  );
  final removedReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'aliceDuringTimelineRemoval',
    text: removedSent['text'] as String,
    senderPeerId: alicePeerId,
  );
  writeSharedText(_signalName('bob_received_aliceDuringTimelineRemoval'), 'ok');
  final bobRemovedWindowUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  await stack.groupMsgRepo.markAsRead(groupId);

  await _waitForMemberInclusion(
    stack: stack,
    groupId: groupId,
    memberPeerId: charliePeerId,
  );
  writeSharedText(_signalName('bob_membership_readded'), 'ok');

  final afterSent = await waitForSharedJson(
    _signalName('alice_sent_alicePostTimelineReadd.json'),
  );
  final afterReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'alicePostTimelineReadd',
    text: afterSent['text'] as String,
    senderPeerId: alicePeerId,
  );
  writeSharedText(_signalName('bob_received_alicePostTimelineReadd'), 'ok');

  final bobSent = await _sendProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'bobPostTimelineReadd',
    text: 'ML-015 Bob after re-add $_runId',
  );
  await waitForSharedSignal(_signalName('alice_received_bobPostTimelineReadd'));
  await waitForSharedSignal(
    _signalName('charlie_received_bobPostTimelineReadd'),
  );

  final charlieSent = await waitForSharedJson(
    _signalName('charlie_sent_charliePostTimelineReadd.json'),
  );
  final charlieReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'charliePostTimelineReadd',
    text: charlieSent['text'] as String,
    senderPeerId: charliePeerId,
  );
  writeSharedText(_signalName('bob_received_charliePostTimelineReadd'), 'ok');
  final bobPostReaddUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  final up011NotificationCountAfter = _notificationCount(stack);
  final up011NotificationSnapshots = _notificationSnapshots(stack);
  await stack.groupMsgRepo.markAsRead(groupId);
  final bobFinalUnreadCount = await stack.groupMsgRepo.getUnreadCount(groupId);

  final removalTimelineText = _ml015RemovalTimelineText(identities);
  final readdTimelineText = _ml015ReaddTimelineText(identities);
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalEpoch = await _keyEpoch(stack, groupId);
  final timelineOrderMatches = await _timelineOrderContains(
    stack: stack,
    groupId: groupId,
    orderedTexts: <String>[
      readdTimelineText,
      beforeSent['text'] as String,
      removalTimelineText,
      removedSent['text'] as String,
      readdTimelineText,
      afterSent['text'] as String,
      bobSent['text'] as String,
      charlieSent['text'] as String,
    ],
  );
  await _writeVerdict(
    stack: stack,
    groupId: groupId,
    sentMessages: <Map<String, dynamic>>[bobSent],
    receivedMessages: <Map<String, dynamic>>[
      beforeReceived,
      removedReceived,
      afterReceived,
      charlieReceived,
    ],
    extra: <String, dynamic>{
      'ml015TimelineTruthProof': <String, dynamic>{
        'rowId': 'ML-015',
        'receivedBeforeRemovalMessage': true,
        'receivedRemovedWindowMessage': true,
        'receivedAlicePostReaddMessage': true,
        'sentBobPostReaddMessage': true,
        'receivedCharliePostReaddMessage': true,
        'timelineOrderMatchesMembershipIntervals': timelineOrderMatches,
        'timelineContainsRemoval': await _hasTimelineText(
          stack: stack,
          groupId: groupId,
          text: removalTimelineText,
        ),
        'timelineContainsReadd': await _hasTimelineText(
          stack: stack,
          groupId: groupId,
          text: readdTimelineText,
        ),
        'memberListIncludesCharlie': memberPeerIds.contains(charliePeerId),
        'finalEpoch': finalEpoch,
      },
      'up002DurableTimelineProof': await _up002DurableTimelineProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'bob',
      ),
      'up004UnreadChurnProof': <String, dynamic>{
        'rowId': 'UP-004',
        'role': 'bob',
        'liveThreePartyProof': true,
        'preRemovalUnreadCovered': bobPreRemovalUnreadCount >= 1,
        'preRemovalUnreadCount': bobPreRemovalUnreadCount,
        'removedWindowActiveRecipientUnreadCovered':
            bobRemovedWindowUnreadCount >= 1,
        'removedWindowUnreadCount': bobRemovedWindowUnreadCount,
        'postReaddUnreadCount': bobPostReaddUnreadCount,
        'postReaddUnreadIncluded': bobPostReaddUnreadCount >= 1,
        'readClearOnOpen': bobFinalUnreadCount == 0,
        'finalUnreadCountAfterOpen': bobFinalUnreadCount,
      },
      'up006ReaddUiStateProof': await _up006ReaddUiStateProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'bob',
      ),
      'up009ReaddSenderIdentityProof': await _up009ReaddSenderIdentityProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'bob',
        charlieMessageId: charlieSent['messageId'] as String,
      ),
      'up010NotificationRouteProof': await _up010NotificationRouteProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'bob',
        charlieMessageId: charlieSent['messageId'] as String,
      ),
      'up011MutedDeliveryProof': <String, dynamic>{
        'rowId': 'UP-011',
        'role': 'bob',
        'liveThreePartyProof': true,
        'muteProofSource': 'app_peer_core_simulator',
        'groupMutedBeforeTraffic': up011BobMuteApplied,
        'receivedPreRemovalMessage': beforeReceived['persistedCount'] == 1,
        'receivedRemovedWindowMessage': removedReceived['persistedCount'] == 1,
        'receivedAlicePostReaddMessage': afterReceived['persistedCount'] == 1,
        'receivedCharliePostReaddMessage':
            charlieReceived['persistedCount'] == 1,
        'preRemovalUnreadCount': bobPreRemovalUnreadCount,
        'removedWindowUnreadCount': bobRemovedWindowUnreadCount,
        'postReaddUnreadCount': bobPostReaddUnreadCount,
        'deliveryUnreadStateUpdated':
            bobPreRemovalUnreadCount >= 1 &&
            bobRemovedWindowUnreadCount >= 1 &&
            bobPostReaddUnreadCount >= 1,
        'notificationCountBeforeMutedTraffic': up011NotificationCountBefore,
        'notificationCountAfterMutedTraffic': up011NotificationCountAfter,
        'mutedNotificationDelta':
            up011NotificationCountAfter - up011NotificationCountBefore,
        'mutedNotificationsSuppressed':
            up011NotificationCountAfter == up011NotificationCountBefore,
        'notificationSnapshotsAfterMutedTraffic': up011NotificationSnapshots,
        'finalMemberListIncludesAliceBobCharlie':
            memberPeerIds.contains(alicePeerId) &&
            memberPeerIds.contains(stack.identity.peerId) &&
            memberPeerIds.contains(charliePeerId),
        'finalEpoch': finalEpoch,
      },
    },
  );
}

Future<void> _runMl015Charlie(
  GroupMultiDeviceTestStack stack,
  Map<String, Map<String, dynamic>> identities,
) async {
  final fixture = await waitForSharedJson(
    _signalName('charlie_initial_group_fixture.json'),
  );
  final groupId = await _importGm004JoinedGroupFixture(
    stack: stack,
    fixture: fixture,
  );
  writeSharedText(_signalName('charlie_group_joined'), 'ok');

  final alicePeerId = identities['alice']!['peerId'] as String;
  final bobPeerId = identities['bob']!['peerId'] as String;
  final charliePeerId = identities['charlie']!['peerId'] as String;
  final initialAddTimelineText = _ml015ReaddTimelineText(identities);

  await waitForCondition(() async {
    return _hasTimelineText(
      stack: stack,
      groupId: groupId,
      text: initialAddTimelineText,
    );
  }, timeout: const Duration(seconds: 120));
  writeSharedText(_signalName('charlie_initial_charlie_added'), 'ok');

  final beforeSent = await waitForSharedJson(
    _signalName('alice_sent_aliceBeforeTimelineRemoval.json'),
  );
  final beforeReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'aliceBeforeTimelineRemoval',
    text: beforeSent['text'] as String,
    senderPeerId: alicePeerId,
  );
  writeSharedText(
    _signalName('charlie_received_aliceBeforeTimelineRemoval'),
    'ok',
  );
  final charliePreRemovalUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  await stack.groupMsgRepo.markAsRead(groupId);

  await _waitForSelfRemoval(stack: stack, groupId: groupId);
  writeSharedText(_signalName('charlie_self_removed'), 'ok');
  await stack.groupMsgRepo.markAsRead(groupId);

  final removedSent = await waitForSharedJson(
    _signalName('alice_sent_aliceDuringTimelineRemoval.json'),
  );
  await Future<void>.delayed(const Duration(seconds: 5));
  final removedWindowPlaintextBeforeReadd = await _proofMessageCount(
    stack: stack,
    groupId: groupId,
    text: removedSent['text'] as String,
    senderPeerId: alicePeerId,
  );
  final charlieRemovedWindowUnreadCount = await stack.groupMsgRepo
      .getUnreadCount(groupId);

  final readdFixture = await waitForSharedJson(
    _signalName('charlie_readd_group_fixture.json'),
  );
  await _importGm004JoinedGroupFixture(stack: stack, fixture: readdFixture);
  writeSharedText(_signalName('charlie_group_rejoined'), 'ok');
  await stack.groupMsgRepo.markAsRead(groupId);

  final afterSent = await waitForSharedJson(
    _signalName('alice_sent_alicePostTimelineReadd.json'),
  );
  final afterReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'alicePostTimelineReadd',
    text: afterSent['text'] as String,
    senderPeerId: alicePeerId,
  );
  writeSharedText(_signalName('charlie_received_alicePostTimelineReadd'), 'ok');

  final bobSent = await waitForSharedJson(
    _signalName('bob_sent_bobPostTimelineReadd.json'),
  );
  final bobReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'bobPostTimelineReadd',
    text: bobSent['text'] as String,
    senderPeerId: bobPeerId,
  );
  writeSharedText(_signalName('charlie_received_bobPostTimelineReadd'), 'ok');
  final charliePostReaddUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );
  await stack.groupMsgRepo.markAsRead(groupId);
  final charlieFinalUnreadCount = await stack.groupMsgRepo.getUnreadCount(
    groupId,
  );

  final charlieSent = await _sendProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'charliePostTimelineReadd',
    text: 'ML-015 Charlie after re-add $_runId',
  );
  await waitForSharedSignal(
    _signalName('alice_received_charliePostTimelineReadd'),
  );
  await waitForSharedSignal(
    _signalName('bob_received_charliePostTimelineReadd'),
  );

  final removedWindowPlaintextAfterReadd = await _proofMessageCount(
    stack: stack,
    groupId: groupId,
    text: removedSent['text'] as String,
    senderPeerId: alicePeerId,
  );

  final readdTimelineText = _ml015ReaddTimelineText(identities);
  final memberPeerIds = await _memberPeerIds(stack, groupId);
  final finalEpoch = await _keyEpoch(stack, groupId);
  final timelineOrderMatches = await _timelineOrderContains(
    stack: stack,
    groupId: groupId,
    orderedTexts: <String>[
      readdTimelineText,
      beforeSent['text'] as String,
      readdTimelineText,
      afterSent['text'] as String,
      bobSent['text'] as String,
      charlieSent['text'] as String,
    ],
  );
  await _writeVerdict(
    stack: stack,
    groupId: groupId,
    sentMessages: <Map<String, dynamic>>[charlieSent],
    receivedMessages: <Map<String, dynamic>>[
      beforeReceived,
      afterReceived,
      bobReceived,
    ],
    extra: <String, dynamic>{
      'ml015TimelineTruthProof': <String, dynamic>{
        'rowId': 'ML-015',
        'receivedBeforeRemovalMessage': true,
        'receivedAlicePostReaddMessage': true,
        'receivedBobPostReaddMessage': true,
        'sentCharliePostReaddMessage': true,
        'selfRemovalCleanupObserved': true,
        'memberListIncludesAliceBob':
            memberPeerIds.contains(alicePeerId) &&
            memberPeerIds.contains(bobPeerId),
        'timelineOrderMatchesMembershipIntervals': timelineOrderMatches,
        'timelineContainsReadd': await _hasTimelineText(
          stack: stack,
          groupId: groupId,
          text: readdTimelineText,
        ),
        'memberListIncludesCharlie': memberPeerIds.contains(charliePeerId),
        'removedWindowPlaintextCount':
            removedWindowPlaintextBeforeReadd +
            removedWindowPlaintextAfterReadd,
        'hasStaleEpochAfterReadd': finalEpoch < 2,
        'finalEpoch': finalEpoch,
      },
      'up002DurableTimelineProof': await _up002DurableTimelineProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'charlie',
      ),
      'up004UnreadChurnProof': <String, dynamic>{
        'rowId': 'UP-004',
        'role': 'charlie',
        'liveThreePartyProof': true,
        'preRemovalUnreadCovered': charliePreRemovalUnreadCount >= 1,
        'preRemovalUnreadCount': charliePreRemovalUnreadCount,
        'removedWindowUnreadExcluded': charlieRemovedWindowUnreadCount == 0,
        'removedWindowUnreadCount': charlieRemovedWindowUnreadCount,
        'removedWindowPlaintextCount':
            removedWindowPlaintextBeforeReadd +
            removedWindowPlaintextAfterReadd,
        'postReaddUnreadCount': charliePostReaddUnreadCount,
        'postReaddUnreadIncluded': charliePostReaddUnreadCount >= 1,
        'readClearOnOpen': charlieFinalUnreadCount == 0,
        'finalUnreadCountAfterOpen': charlieFinalUnreadCount,
      },
      'up006ReaddUiStateProof': await _up006ReaddUiStateProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'charlie',
      ),
      'up009ReaddSenderIdentityProof': await _up009ReaddSenderIdentityProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'charlie',
        charlieMessageId: charlieSent['messageId'] as String,
      ),
      'up010NotificationRouteProof': await _up010NotificationRouteProof(
        stack: stack,
        groupId: groupId,
        identities: identities,
        role: 'charlie',
        charlieMessageId: charlieSent['messageId'] as String,
      ),
    },
  );
}

Future<Map<String, dynamic>> _gm015PolicyProof({
  required GroupMultiDeviceTestStack stack,
  required String groupId,
  required String alicePeerId,
  required String bobPeerId,
  required String charliePeerId,
  required int initialKeyEpoch,
  Map<String, dynamic> extra = const <String, dynamic>{},
}) async {
  final group = await stack.groupRepo.getGroup(groupId);
  final members = await stack.groupRepo.getMembers(groupId);
  final memberPeerIds = members
      .map((member) => member.peerId)
      .toList(growable: false);
  final adminPeerIds = members
      .where((member) => member.role == MemberRole.admin)
      .map((member) => member.peerId)
      .toList(growable: false);
  final expectedMembers = <String>{alicePeerId, bobPeerId, charliePeerId};
  final finalKeyEpoch = await _keyEpoch(stack, groupId);
  final memberSet = memberPeerIds.toSet();
  final mutated =
      group == null ||
      group.isDissolved ||
      finalKeyEpoch != initialKeyEpoch ||
      memberPeerIds.length != expectedMembers.length ||
      memberSet.length != expectedMembers.length ||
      !memberSet.containsAll(expectedMembers) ||
      adminPeerIds.length != 1 ||
      adminPeerIds.single != alicePeerId;

  return <String, dynamic>{
    'groupPresent': group != null,
    'groupDissolved': group?.isDissolved ?? false,
    'creatorPeerId': group?.createdBy,
    'finalMemberPeerIds': memberPeerIds,
    'adminPeerIds': adminPeerIds,
    'memberListHasActiveAdmin': adminPeerIds.isNotEmpty,
    'mutationAfterBlockedAttempt': mutated,
    'keyEpochUnchanged': finalKeyEpoch == initialKeyEpoch,
    'initialKeyEpoch': initialKeyEpoch,
    'finalKeyEpoch': finalKeyEpoch,
    ...extra,
  };
}

Future<void> _runGm015Alice(
  GroupMultiDeviceTestStack stack,
  Map<String, Map<String, dynamic>> identities,
) async {
  final fixture = await _createGroupFixture(
    stack: stack,
    identities: identities,
    memberRoles: const <String>['bob', 'charlie'],
    name: 'GM-015 Private Group',
  );
  writeSharedJson(_signalName('group_fixture.json'), fixture);
  final groupId = (fixture['group'] as Map)['id'] as String;

  await waitForSharedSignal(_signalName('bob_group_joined'));
  await waitForSharedSignal(_signalName('charlie_group_joined'));
  await Future<void>.delayed(const Duration(seconds: 5));

  final alicePeerId = stack.identity.peerId;
  final bobPeerId = identities['bob']!['peerId'] as String;
  final charliePeerId = identities['charlie']!['peerId'] as String;
  final initialKeyEpoch = await _keyEpoch(stack, groupId);

  var selfRemovalOutcome = 'notRun';
  String? selfRemovalReason;
  try {
    await removeGroupMember(
      bridge: stack.bridge,
      groupRepo: stack.groupRepo,
      groupId: groupId,
      memberPeerId: alicePeerId,
      selfPeerId: alicePeerId,
      actorUsername: stack.identity.username,
      msgRepo: stack.groupMsgRepo,
    );
    selfRemovalOutcome = 'success';
  } on StateError catch (error) {
    selfRemovalOutcome = 'blocked';
    selfRemovalReason = error.message;
  }

  final group = await stack.groupRepo.getGroup(groupId);
  if (group == null) {
    throw StateError('GM-015 group disappeared after self-removal attempt');
  }
  final broadcastResult = await broadcastVoluntaryLeaveAndRotateKey(
    bridge: stack.bridge,
    groupRepo: stack.groupRepo,
    group: group,
    identityRepo: stack.identityRepo,
    msgRepo: stack.groupMsgRepo,
    sendP2PMessage: (peerId, message) async {
      return stack.p2pService.sendMessage(peerId, message);
    },
  );
  final voluntaryLeaveBroadcastOutcome = broadcastResult.didBroadcast
      ? 'broadcast'
      : 'skipped';

  var leaveOutcome = 'notRun';
  String? leaveReason;
  try {
    await leaveGroup(
      bridge: stack.bridge,
      groupRepo: stack.groupRepo,
      groupId: groupId,
    );
    leaveOutcome = 'success';
  } on StateError catch (error) {
    leaveOutcome = 'blocked';
    leaveReason = error.message;
  }

  final attempts = <String, dynamic>{
    'selfRemovalOutcome': selfRemovalOutcome,
    'selfRemovalReason': selfRemovalReason,
    'voluntaryLeaveBroadcastOutcome': voluntaryLeaveBroadcastOutcome,
    'voluntaryLeaveBroadcastSkipReason': broadcastResult.skipReason?.name,
    'leaveOutcome': leaveOutcome,
    'leaveReason': leaveReason,
    'initialKeyEpoch': initialKeyEpoch,
  };
  writeSharedJson(_signalName('gm015_policy_attempts.json'), attempts);

  final bobSent = await waitForSharedJson(
    _signalName('bob_sent_bobAfterBlockedAdminSelfRemoval.json'),
  );
  final bobReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'bobAfterBlockedAdminSelfRemoval',
    text: bobSent['text'] as String,
    senderPeerId: bobPeerId,
  );

  final charlieSent = await waitForSharedJson(
    _signalName('charlie_sent_charlieAfterBlockedAdminLeave.json'),
  );
  final charlieReceived = await _waitForReceivedProofMessage(
    stack: stack,
    groupId: groupId,
    key: 'charlieAfterBlockedAdminLeave',
    text: charlieSent['text'] as String,
    senderPeerId: charliePeerId,
  );

  await _writeVerdict(
    stack: stack,
    groupId: groupId,
    sentMessages: const <Map<String, dynamic>>[],
    receivedMessages: <Map<String, dynamic>>[bobReceived, charlieReceived],
    extra: <String, dynamic>{
      'gm015AdminSelfRemovalPolicyProof': await _gm015PolicyProof(
        stack: stack,
        groupId: groupId,
        alicePeerId: alicePeerId,
        bobPeerId: bobPeerId,
        charliePeerId: charliePeerId,
        initialKeyEpoch: initialKeyEpoch,
        extra: <String, dynamic>{
          ...attempts,
          'receivedBobPostAttemptSend': true,
          'receivedCharliePostAttemptSend': true,
        },
      ),
    },
  );
}

